import { EventEmitter } from "eventemitter3";
import type { AudioEffect } from "./BaseEffect.js";
import { clampVolume } from "./utils.js";

export class FadeEffect extends EventEmitter implements AudioEffect {
  readonly name = "fade";

  private _active = false;
  private _from = 1;
  private _to = 1;
  private _samplesTotal = 0;
  private _samplesDone = 0;
  private _sampleRate: number;

  private _volume: number;

  constructor(volume: number, sampleRate: number) {
    super();
    this._volume = volume;
    this._sampleRate = sampleRate;
  }

  get volume(): number {
    return this._volume;
  }

  get active(): boolean {
    return this._active;
  }

  setVolume(v: number): void {
    this._volume = clampVolume(v);
  }

  startFade(targetVolume: number, durationMs: number): void {
    const to = clampVolume(targetVolume);
    const samples = Math.max(1, Math.round((durationMs / 1000) * this._sampleRate));

    this._from = this._volume;
    this._to = to;
    this._samplesTotal = samples;
    this._samplesDone = 0;
    this._active = true;

    this.emit("fade-start", { from: this._from, to: this._to, durationMs });
  }

  isActive(): boolean {
    return this._active;
  }

  process(samples: Float64Array, channels: number, _frames: number): void {
    if (!this._active) return;

    for (let i = 0; i < samples.length; i += channels) {
      const progress = this._samplesTotal > 0 ? Math.min(1, this._samplesDone / this._samplesTotal) : 1;
      const currentVolume = this._from + (this._to - this._from) * progress;
      this._samplesDone++;

      for (let ch = 0; ch < channels; ch++) {
        samples[i + ch] = samples[i + ch]! * currentVolume;
      }

      if (this._samplesDone >= this._samplesTotal) {
        this._volume = this._to;
        this._active = false;
        this._samplesDone = 0;
        this._samplesTotal = 0;
        this.emit("fade-end", { to: this._to });
        break;
      }
    }
  }

  reset(): void {
    this._active = false;
    this._samplesDone = 0;
    this._samplesTotal = 0;
  }
}
